        "var lbl=document.getElementById(\'timer-lbl-\'+vid);"
        "if(sec){"
        "if(diff>=7){sec.style.display=\'block\';if(lbl)lbl.textContent=\'\';"
        "}else{sec.style.display=\'none\';if(lbl)lbl.textContent=\'&#9749; Order options in \'+(7-diff)+\' min\';}"
        "}"
